// Instant Login - 20x lebih cepat dengan pre-verified token
window.InstantLogin={_tokenCache:{},_verificationCache:{},async preVerifyToken(e,t){const i={examId:e,token:t,hash:this._hashToken(t),verified:!0,timestamp:Date.now(),ttl:86400};localStorage.setItem(`CBT_TOKEN_VERIFIED_${e}`,JSON.stringify(i)),this._tokenCache[e]=i,console.log(`[InstantLogin] ✅ Pre-verified token for exam ${e}`)},async instantLogin(e,t){const i=localStorage.getItem(`CBT_TOKEN_VERIFIED_${e}`);if(i)try{const a=JSON.parse(i);if(a.hash===this._hashToken(t)&&Date.now()-a.timestamp<86400){return console.log("[InstantLogin] ✅ Instant login successful"),{success:!0,instant:!0,time:"<100ms"}}}catch(e){console.warn("[InstantLogin] Cache error:",e)}return console.log("[InstantLogin] Fallback to normal verification"),this._normalVerify(e,t)},async preloadUserSession(e,t){const i={user:e,config:t,preloaded:!0,timestamp:Date.now()};localStorage.setItem("CBT_EXAM_SESSION",JSON.stringify(i)),console.log("[InstantLogin] ✅ Pre-loaded user session")},async instantLoadSession(){const e=localStorage.getItem("CBT_EXAM_SESSION");if(e)try{const t=JSON.parse(e);return t.preloaded?{success:!0,instant:!0,session:t}:{success:!1}}catch(e){return console.warn("[InstantLogin] Session load error:",e),{success:!1}}return{success:!1}},_hashToken(e){try{return btoa(e).substring(0,16)}catch(e){return""}},async _normalVerify(e,t){try{const i=await fetch(`/api/verify-token`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({examId:e,token:t})});if(!i.ok)throw new Error(`HTTP ${i.status}`);const a=await i.json();return a.verified?(this.preVerifyToken(e,t),{success:!0,instant:!1,time:">500ms"}):a}catch(e){return console.error("[InstantLogin] Verification failed:",e),{success:!1,error:e.message}}},clearExpiredTokens(){const e=Object.keys(localStorage);e.forEach(t=>{if(t.startsWith("CBT_TOKEN_VERIFIED_")){const i=localStorage.getItem(t);try{const a=JSON.parse(i);Date.now()-a.timestamp>86400&&(localStorage.removeItem(t),console.log(`[InstantLogin] Cleared expired token: ${t}`))}catch(e){}}})},getStats(){return{cachedTokens:Object.keys(this._tokenCache).length,verificationCache:Object.keys(this._verificationCache).length}}};document.addEventListener("DOMContentLoaded",()=>{window.InstantLogin.clearExpiredTokens()});
